1	// ABI contract for hybrid handoff state: magic/version, layout, roundtrip.
2	
3	#include "hybrid/state_abi.h"
4	
5	#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
6	#include <doctest.h>
7	
8	#include <cstdint>
9	#include <cstring>
10	#include <type_traits>
11	
12	TEST_CASE("magic and version are stable wire constants")
13	{
14	  CHECK(HYBRID_STATE_MAGIC == 0x42594841u);
15	  CHECK(HYBRID_STATE_VERSION == 1u);
16	}
17	
18	TEST_CASE("struct is standard-layout, trivially copyable, no tail padding")
19	{
20	  CHECK(std::is_standard_layout_v<hybrid_state_v1>);
21	  CHECK(std::is_trivially_copyable_v<hybrid_state_v1>);
22	  CHECK(sizeof(hybrid_state_v1) % 8 == 0);
23	}
24	
25	TEST_CASE("header field offsets")
26	{
27	  CHECK(offsetof(hybrid_state_v1, magic) == 0);
28	  CHECK(offsetof(hybrid_state_v1, version) == 4);
29	  CHECK(offsetof(hybrid_state_v1, flags) == 8);
30	  CHECK(offsetof(hybrid_state_v1, hart_id) == 12);
31	  CHECK(offsetof(hybrid_state_v1, pc) == 16);
32	  CHECK(offsetof(hybrid_state_v1, priv) == 24);
33	}
34	
35	TEST_CASE("GPR and FPR are 32 * uint64_t each, contiguous")
36	{
37	  hybrid_state_v1 s{};
38	  CHECK(offsetof(hybrid_state_v1, gpr) == 32);
39	  CHECK(sizeof(s.gpr) == 32 * sizeof(uint64_t));
40	  CHECK(offsetof(hybrid_state_v1, fpr) == 32 + 32 * 8);
41	  CHECK(sizeof(s.fpr) == 32 * sizeof(uint64_t));
42	}
43	
44	TEST_CASE("V-extension fields use compile-time MAX_VLEN constant")
45	{
46	  hybrid_state_v1 s{};
47	  CHECK(HYBRID_VLEN_BYTES_MAX >= 16);  // RVV minimum VLEN=128 -> 16 bytes
48	  CHECK((HYBRID_VLEN_BYTES_MAX & (HYBRID_VLEN_BYTES_MAX - 1)) == 0);  // power of 2
49	  CHECK(sizeof(s.vreg) == 32u * HYBRID_VLEN_BYTES_MAX);
50	}
51	
52	TEST_CASE("PMP arrays are sized per spec")
53	{
54	  hybrid_state_v1 s{};
55	  CHECK(sizeof(s.pmpcfg) == HYBRID_PMP_CFG_NUM * sizeof(uint64_t));
56	  CHECK(sizeof(s.pmpaddr) == HYBRID_PMP_ADDR_NUM * sizeof(uint64_t));
57	  CHECK(HYBRID_PMP_ADDR_NUM == 64);
58	  CHECK(HYBRID_PMP_CFG_NUM == 16);
59	}
60	
61	TEST_CASE("trailing reserved padding is at least 256 bytes")
62	{
63	  hybrid_state_v1 s{};
64	  CHECK(sizeof(s.reserved) >= 256);
65	}
66	
67	TEST_CASE("byte-level roundtrip via memcpy preserves all fields")
68	{
69	  hybrid_state_v1 src{};
70	  src.magic = HYBRID_STATE_MAGIC;
71	  src.version = HYBRID_STATE_VERSION;
72	  src.flags = HYBRID_FLAG_RV64 | HYBRID_FLAG_FP | HYBRID_FLAG_V;
73	  src.hart_id = 1;
74	  src.pc = 0x80001234ULL;
75	  src.priv = 3;  // M-mode
76	
77	  for (int i = 0; i < 32; ++i) {
78	    src.gpr[i] = 0xCAFE0000ULL + i;
79	    src.fpr[i] = 0xF00D0000ULL + i;
80	  }
81	  src.mstatus = 0xa00040080ULL;
82	  src.mepc    = 0x80002000ULL;
83	  src.mtvec   = 0x80000000ULL;
84	  src.satp    = 0x8000000000080000ULL;
85	  src.vstart  = 0;
86	  src.vtype   = 0xc0;
87	  src.vl      = 4;
88	  src.vlenb   = 16;
89	  for (size_t i = 0; i < sizeof(src.vreg); ++i) src.vreg[i] = (uint8_t) i;
90	
91	  alignas(hybrid_state_v1) unsigned char buf[sizeof(hybrid_state_v1)];
92	  std::memcpy(buf, &src, sizeof(src));
93	  hybrid_state_v1 dst{};
94	  std::memcpy(&dst, buf, sizeof(dst));
95	
96	  CHECK(dst.magic == HYBRID_STATE_MAGIC);
97	  CHECK(dst.version == HYBRID_STATE_VERSION);
98	  CHECK(dst.flags == src.flags);
99	  CHECK(dst.hart_id == 1);
100	  CHECK(dst.pc == 0x80001234ULL);
101	  CHECK(dst.priv == 3);
102	  for (int i = 0; i < 32; ++i) {
103	    CHECK(dst.gpr[i] == 0xCAFE0000ULL + i);
104	    CHECK(dst.fpr[i] == 0xF00D0000ULL + i);
105	  }
106	  CHECK(dst.mstatus == 0xa00040080ULL);
107	  CHECK(dst.mepc == 0x80002000ULL);
108	  CHECK(dst.mtvec == 0x80000000ULL);
109	  CHECK(dst.satp == 0x8000000000080000ULL);
110	  CHECK(dst.vtype == 0xc0);
111	  CHECK(dst.vl == 4);
112	  CHECK(dst.vlenb == 16);
113	  CHECK(std::memcmp(dst.vreg, src.vreg, sizeof(src.vreg)) == 0);
114	}
115	
116	TEST_CASE("flag bits are stable wire constants")
117	{
118	  CHECK(HYBRID_FLAG_RV64 == (1u << 0));
119	  CHECK(HYBRID_FLAG_FP   == (1u << 1));
120	  CHECK(HYBRID_FLAG_V    == (1u << 2));
121	}
